-      size_t playHead1 = (reverseIndex - scale * i ) % buffer->size; // reverse playhead
-
-      SAMPLE sample = *in++; /* MONO input */
-
-      float value = sigmoid(0.5 * sample + 0.5 * buffer->buffer[playHead1]);
