-    // Calculate mean
-    var sum: f32 = 0.0;
-    for (var i: u32 = 0; i < C; i = i + 1) {
-        sum += inp[idx * C + i];
-    }
-    let mean_val: f32 = sum / f32(C);
-
-    // Calculate rstd
-    sum = 0.0;
