+    "voronoi.wgsl",
+    "fluid.wgsl",
+    "aurora.wgsl",
+    "julia.wgsl",
+    "mandelbrot.wgsl",
+    "particles.wgsl",
+    "default.wgsl",
+]  # Add more file names as needed
+
+
+def copy_file(src, dst):
+    try:
+        shutil.copy(src, dst)
+        print(f"Copied {src} to {dst}")
+    except IOError as e:
+        print(f"Unable to copy file. {e}")
+    except:
