+    workgroupBarrier();
+
+    var acc = 0.0;
+
+    for (var i: u32 = 0u; i < arrayLength(&b); i = i + 1u) {
+      if (idx + i < arrayLength(&a)) {
+        acc = acc + shared_a[local_idx + i] * shared_b[i];
