+};
+@compute @workgroup_size({{workgroupSize}})
+fn main(
+  @builtin(global_invocation_id) GlobalInvocationID: vec3<u32>
+  ) {
+    let idx = GlobalInvocationID.x + GlobalInvocationID.y * params.size;
+
+    if (idx < params.size) {
