+const char *kPuzzle8 = R"(
+@group(0) @binding(0) var<storage, read_write> a: array<f32>;
+@group(0) @binding(1) var<storage, read_write> output : array<f32>;
+@group(0) @binding(2) var<uniform> params: Params;
