+  for (size_t i = 0; i < n; i++) {
+    if (std::abs(a[i] - b[i]) > tol || std::isnan(a[i]) || std::isnan(b[i])) {
+      LOG(kDefLog, kInfo, "Mismatch at index %d: %f != %f", i, a[i], b[i]);
+      return false;
+    }
+  }
+  return true;
